1	/***************************************************************************************
2	 * Output fabric key of Module Graph to file formats
3	 ***************************************************************************************/
4	/* Headers from vtrutil library */
5	#include "vtr_assert.h"
6	#include "vtr_log.h"
7	#include "vtr_time.h"
8	
9	/* Headers from openfpgautil library */
10	#include "command_exit_codes.h"
11	#include "openfpga_digest.h"
12	
13	/* Headers from archopenfpga library */
14	#include "fabric_key_writer.h"
15	#include "memory_utils.h"
