18	
19	/* begin namespace openfpga */
20	namespace openfpga {
21	
22	/***************************************************************************************
23	 * Add module-level keys to fabric key
24	 ***************************************************************************************/
25	static int add_module_keys_to_fabric_key(const ModuleManager& module_manager,
26	                                         const ModuleId& curr_module,
27	                                         FabricKey& fabric_key) {
28	  /* Bypass top-level module */
29	  std::string module_name = module_manager.module_name(curr_module);
30	  if (module_name == generate_fpga_top_module_name() ||
31	      module_name == generate_fpga_core_module_name()) {
32	    return CMD_EXEC_SUCCESS;
33	  }
34	  /* Bypass modules which does not have any configurable children */
35	  if (module_manager
36	        .configurable_children(curr_module,
37	                               ModuleManager::e_config_child_type::PHYSICAL)
38	        .empty()) {
39	    return CMD_EXEC_SUCCESS;
40	  }
41	  /* Now create the module and add subkey one by one */
42	  FabricKeyModuleId key_module_id = fabric_key.create_module(module_name);
43	  if (!key_module_id) {
44	    return CMD_EXEC_FATAL_ERROR;
45	  }
46	  size_t num_config_child =
47	    module_manager
48	      .configurable_children(curr_module,
49	                             ModuleManager::e_config_child_type::PHYSICAL)
50	      .size();
51	  for (size_t ichild = 0; ichild < num_config_child; ++ichild) {
52	    ModuleId child_module = module_manager.configurable_children(
53	      curr_module, ModuleManager::e_config_child_type::PHYSICAL)[ichild];
54	    size_t child_instance = module_manager.configurable_child_instances(
55	      curr_module, ModuleManager::e_config_child_type::PHYSICAL)[ichild];
56	
57	    FabricSubKeyId sub_key = fabric_key.create_module_key(key_module_id);
58	    fabric_key.set_sub_key_name(sub_key,
59	                                module_manager.module_name(child_module));
60	    fabric_key.set_sub_key_value(sub_key, child_instance);
61	
62	    if (false ==
63	        module_manager.instance_name(curr_module, child_module, child_instance)
64	          .empty()) {
65	      fabric_key.set_sub_key_alias(
66	        sub_key, module_manager.instance_name(curr_module, child_module,
67	                                              child_instance));
68	    }
69	  }
70	  return CMD_EXEC_SUCCESS;
71	}
72	
73	/***************************************************************************************
74	 * Write the fabric key of top module to an XML file
75	 * We will use the writer API in libfabrickey
76	 *
77	 * Return 0 if successful
78	 * Return 1 if there are more serious bugs in the architecture
79	 * Return 2 if fail when creating files
80	 ***************************************************************************************/
81	int write_fabric_key_to_xml_file(
82	  const ModuleManager& module_manager, const std::string& fname,
83	  const ConfigProtocol& config_protocol,
84	  const MemoryBankShiftRegisterBanks& blwl_sr_banks,
85	  const bool& include_module_keys, const bool& verbose) {
86	  int err_code = CMD_EXEC_SUCCESS;
87	  std::string timer_message =
88	    std::string("Write fabric key to XML file '") + fname + std::string("'");
89	
90	  std::string dir_path = format_dir_path(find_path_dir_name(fname));
91	
92	  /* Create directories */
93	  create_directory(dir_path, true, verbose);
94	
95	  /* Start time count */
96	  vtr::ScopedStartFinishTimer timer(timer_message);
97	
98	  /* Use default name if user does not provide one */
99	  VTR_ASSERT(true != fname.empty());
100	
101	  /* Find top-level module */
102	  std::string top_module_name = generate_fpga_top_module_name();
103	  ModuleId top_module = module_manager.find_module(top_module_name);
104	  std::string core_module_name = generate_fpga_core_module_name();
105	  ModuleId core_module = module_manager.find_module(core_module_name);
106	  if (!module_manager.valid_module_id(top_module) &&
107	      !module_manager.valid_module_id(core_module)) {
108	    VTR_LOGV_ERROR(
109	      verbose, "Unable to find the top-level/core-level module '%s' or '%s'!\n",
110	      top_module_name.c_str(), core_module_name.c_str());
111	    return CMD_EXEC_FATAL_ERROR;
112	  }
113	  if (module_manager.valid_module_id(top_module) &&
114	      module_manager.valid_module_id(core_module)) {
115	    top_module = core_module;
116	  }
117	
118	  /* Build a fabric key database by visiting all the configurable children */
119	  FabricKey fabric_key;
120	  size_t num_keys =
121	    module_manager
122	      .configurable_children(top_module,
123	                             ModuleManager::e_config_child_type::PHYSICAL)
124	      .size();
125	
126	  fabric_key.reserve_keys(num_keys);
127	
128	  size_t num_regions = module_manager.regions(top_module).size();
129	  fabric_key.reserve_regions(num_regions);
130	
131	  /* Create regions and build a id map */
132	  std::map<ConfigRegionId, FabricRegionId> region_id_map;
133	  for (const ConfigRegionId& config_region :
134	       module_manager.regions(top_module)) {
135	    FabricRegionId fabric_region = fabric_key.create_region();
136	    region_id_map[config_region] = fabric_region;
137	  }
138	
139	  /* Create regions for the keys and load keys by region */
140	  for (const ConfigRegionId& config_region :
141	       module_manager.regions(top_module)) {
142	    /* Must have a valid one-to-one region mapping  */
143	    auto result = region_id_map.find(config_region);
144	    VTR_ASSERT_SAFE(result != region_id_map.end());
145	    FabricRegionId fabric_region = result->second;
146	
147	    /* Each configuration protocol has some child which should not be in the
148	     * list. They are typically decoders */
149	    size_t curr_region_num_config_child =
150	      module_manager.region_configurable_children(top_module, config_region)
151	        .size();
152	    size_t num_child_to_skip =
153	      estimate_num_configurable_children_to_skip_by_config_protocol(
154	        config_protocol, curr_region_num_config_child);
155	    curr_region_num_config_child -= num_child_to_skip;
156	
157	    fabric_key.reserve_region_keys(fabric_region, curr_region_num_config_child);
158	
159	    for (size_t ichild = 0; ichild < curr_region_num_config_child; ++ichild) {
160	      ModuleId child_module = module_manager.region_configurable_children(
161	        top_module, config_region)[ichild];
162	      size_t child_instance =
163	        module_manager.region_configurable_child_instances(
164	          top_module, config_region)[ichild];
165	      vtr::Point<int> child_coord =
166	        module_manager.region_configurable_child_coordinates(
167	          top_module, config_region)[ichild];
168	
169	      FabricKeyId key = fabric_key.create_key();
170	      fabric_key.set_key_name(key, module_manager.module_name(child_module));
171	      fabric_key.set_key_value(key, child_instance);
172	
173	      if (false ==
174	          module_manager.instance_name(top_module, child_module, child_instance)
175	            .empty()) {
176	        fabric_key.set_key_alias(
177	          key, module_manager.instance_name(top_module, child_module,
178	                                            child_instance));
179	      }
180	
181	      /* Add key coordinate */
182	      fabric_key.set_key_coordinate(key, child_coord);
183	
184	      /* Add keys to the region */
185	      fabric_key.add_key_to_region(fabric_region, key);
186	    }
187	  }
188	
189	  /* Skip invalid region, some architecture may not have BL/WL banks */
190	  if (0 < blwl_sr_banks.regions().size()) {
191	    /* Add BL shift register bank information, if there is any */
192	    for (const ConfigRegionId& config_region :
193	         module_manager.regions(top_module)) {
194	      auto result = region_id_map.find(config_region);
195	      /* Must have a valid one-to-one region mapping  */
196	      VTR_ASSERT_SAFE(result != region_id_map.end());
197	      FabricRegionId fabric_region = result->second;
198	      for (const FabricBitLineBankId& bank :
199	           blwl_sr_banks.bl_banks(config_region)) {
200	        FabricBitLineBankId fabric_bank =
201	          fabric_key.create_bl_shift_register_bank(fabric_region);
202	        for (const BasicPort& data_port :
203	             blwl_sr_banks.bl_bank_data_ports(config_region, bank)) {
204	          fabric_key.add_data_port_to_bl_shift_register_bank(
205	            fabric_region, fabric_bank, data_port);
206	        }
207	      }
208	    }
209	
210	    /* Add WL shift register bank information, if there is any */
211	    for (const ConfigRegionId& config_region :
212	         module_manager.regions(top_module)) {
213	      auto result = region_id_map.find(config_region);
214	      /* Must have a valid one-to-one region mapping  */
215	      VTR_ASSERT_SAFE(result != region_id_map.end());
216	      FabricRegionId fabric_region = result->second;
217	
218	      for (const FabricWordLineBankId& bank :
219	           blwl_sr_banks.wl_banks(config_region)) {
220	        FabricWordLineBankId fabric_bank =
221	          fabric_key.create_wl_shift_register_bank(fabric_region);
222	        for (const BasicPort& data_port :
223	             blwl_sr_banks.wl_bank_data_ports(config_region, bank)) {
224	          fabric_key.add_data_port_to_wl_shift_register_bank(
225	            fabric_region, fabric_bank, data_port);
226	        }
227	      }
228	    }
229	  }
230	
231	  VTR_LOGV(verbose, "Created %lu regions and %lu keys for the top module %s.\n",
232	           num_regions, num_keys, top_module_name.c_str());
233	
234	  /* Output module subkeys if specified */
235	  if (include_module_keys) {
236	    for (ModuleId submodule : module_manager.modules()) {
237	      err_code =
238	        add_module_keys_to_fabric_key(module_manager, submodule, fabric_key);
239	      if (err_code != CMD_EXEC_SUCCESS) {
240	        return CMD_EXEC_FATAL_ERROR;
241	      }
242	    }
243	  }
244	
245	  /* Call the XML writer for fabric key */
246	  err_code = write_xml_fabric_key(fname.c_str(), fabric_key);
247	
248	  return err_code;
249	}
250	
251	} /* end namespace openfpga */
