1	/***************************************************************************************
2	 * Output internal structure of Module Graph hierarchy to file formats
3	 ***************************************************************************************/
4	#include <regex>
5	/* Headers from vtrutil library */
6	#include "vtr_assert.h"
7	#include "vtr_log.h"
8	#include "vtr_time.h"
9	
10	/* Headers from openfpgautil library */
11	#include "command_exit_codes.h"
12	#include "fabric_hierarchy_writer.h"
13	#include "openfpga_digest.h"
14	#include "openfpga_naming.h"
15	
16	/* begin namespace openfpga */
17	namespace openfpga {
18	
19	/** Identify if the module has no child whose name matches the filter */
20	static bool module_filter_all_children(const ModuleManager& module_manager,
21	                                       const ModuleId& curr_module,
22	                                       const ModuleNameMap& module_name_map,
23	                                       const std::string& module_name_filter) {
24	  for (const ModuleId& child_module :
25	       module_manager.child_modules(curr_module)) {
26	    /* Filter out the names which do not match the pattern */
27	    std::string child_module_name = module_manager.module_name(child_module);
28	    if (module_name_map.name_exist(child_module_name)) {
29	      child_module_name = module_name_map.name(child_module_name);
30	    }
31	    std::string pattern = module_name_filter;
32	    std::regex star_replace("\\*");
33	    std::regex questionmark_replace("\\?");
34	    std::string wildcard_pattern =
35	      std::regex_replace(std::regex_replace(pattern, star_replace, ".*"),
36	                         questionmark_replace, ".");
37	    std::regex wildcard_regex(wildcard_pattern);
38	    if (std::regex_match(child_module_name, wildcard_regex)) {
39	      return false;
40	    }
41	  }
42	  return true;
43	}
44	
45	/***************************************************************************************
46	 * Recursively output child module of the parent_module to a text file
47	 * We use Depth-First Search (DFS) here so that we can output a tree down to
48	 *leaf first Add space (indent) based on the depth in hierarchy e.g. depth = 1
49	 *means a space as indent
50	 ***************************************************************************************/
51	static int rec_output_module_hierarchy_to_text_file(
52	  std::fstream& fp, const size_t& hie_depth_to_stop,
53	  const size_t& current_hie_depth, const ModuleManager& module_manager,
54	  const ModuleId& parent_module, const ModuleNameMap& module_name_map,
55	  const std::string& module_name_filter, const bool& verbose) {
56	  /* Stop if hierarchy depth is beyond the stop line */
57	  if (hie_depth_to_stop < current_hie_depth) {
58	    return CMD_EXEC_SUCCESS;
59	  }
60	
61	  if (false == valid_file_stream(fp)) {
62	    return CMD_EXEC_FATAL_ERROR;
63	  }
64	
65	  /* Check if all the child module has not qualified grand-child, use leaf for
66	   * this level */
67	  bool use_list = true;
68	  for (const ModuleId& child_module :
69	       module_manager.child_modules(parent_module)) {
70	    if (!module_filter_all_children(module_manager, child_module,
71	                                    module_name_map, module_name_filter)) {
72	      use_list = false;
73	      break;
74	    }
75	  }
76	  /* For debug use only
77	  VTR_LOGV(verbose, "Current depth: %lu, Target depth: %lu\n",
78	           current_hie_depth, hie_depth_to_stop);
79	  */
80	  std::string parent_module_name = module_manager.module_name(parent_module);
81	  if (module_name_map.name_exist(parent_module_name)) {
82	    parent_module_name = module_name_map.name(parent_module_name);
83	  }
84	  VTR_LOGV(use_list && verbose,
85	           "Use list as module '%s' contains only leaf nodes\n",
86	           parent_module_name.c_str());
87	
88	  /* Iterate over all the child module */
