1	/********************************************************************
2	 * This file includes functions that are used to build the location
3	 * map information for the top-level module of the FPGA fabric
4	 * It helps OpenFPGA to link the I/O port index in top-level module
5	 * to the VPR I/O mapping results
6	 *******************************************************************/
7	#include <algorithm>
8	#include <map>
9	
10	/* Headers from vtrutil library */
11	#include "vtr_assert.h"
12	#include "vtr_log.h"
13	#include "vtr_time.h"
14	
15	/* Headers from vpr library */
16	#include "build_fabric_io_location_map.h"
17	#include "module_manager_utils.h"
18	#include "openfpga_device_grid_utils.h"
19	#include "openfpga_naming.h"
20	#include "openfpga_reserved_words.h"
21	#include "vpr_utils.h"
22	
23	/* begin namespace openfpga */
24	namespace openfpga {
25	
26	/********************************************************************
27	 * Find all the GPIO ports in the grid module
28	 * and cache their port/pin index in the top-level module
29	 *
30	 * .. note:: The I/O sequence(indexing) is already determined in the
31	 *io_children() list of top-level module. Here we just build a fast lookup from
32	 *(x, y, z) coordinate to the actual indices
33	 *******************************************************************/
34	static IoLocationMap build_fabric_fine_grained_io_location_map(
35	  const ModuleManager& module_manager, const DeviceGrid& grids,
36	  const size_t& layer) {
37	  vtr::ScopedStartFinishTimer timer(
38	    "Create I/O location mapping for top module");
39	
40	  IoLocationMap io_location_map;
41	
42	  std::map<std::string, size_t> io_counter;
43	
44	  std::string top_module_name = generate_fpga_top_module_name();
45	  ModuleId top_module = module_manager.find_module(top_module_name);
46	  VTR_ASSERT(true == module_manager.valid_module_id(top_module));
47	
48	  /* Walk through the I/O child list */
49	  for (size_t ichild = 0;
50	       ichild < module_manager.io_children(top_module).size(); ++ichild) {
51	    ModuleId child = module_manager.io_children(top_module)[ichild];
52	    vtr::Point<int> coord =
53	      module_manager.io_child_coordinates(top_module)[ichild];
54	    t_physical_tile_loc phy_tile_loc(coord.x(), coord.y(), layer);
55	    t_physical_tile_type_ptr phy_tile_type =
56	      grids.get_physical_type(phy_tile_loc);
57	
58	    /* Bypass EMPTY grid */
59	    if (true == is_empty_type(phy_tile_type)) {
60	      continue;
61	    }
62	
63	    /* Skip width or height > 1 tiles (mostly heterogeneous blocks) */
64	    if ((0 < grids.get_width_offset(phy_tile_loc)) ||
65	        (0 < grids.get_height_offset(phy_tile_loc))) {
66	      continue;
67	    }
68	
69	    VTR_ASSERT_SAFE(true == module_manager.valid_module_id(child));
70	
71	    /* Find all the GPIO ports in the grid module */
72	
73	    /* MUST DO: register in io location mapping!
74	     * I/O location mapping is a critical look-up for testbench generators
75	     */
76	    if (size_t(phy_tile_type->capacity) !=
77	        module_manager.io_children(child).size()) {
78	      VTR_LOG("%s[%ld][%ld] capacity: %d while io_child number is %d",
79	              phy_tile_type->name.c_str(), coord.x(), coord.y(),
80	              phy_tile_type->capacity,
81	              module_manager.io_children(child).size());
82	    }
83	    VTR_ASSERT(size_t(phy_tile_type->capacity) ==
84	               module_manager.io_children(child).size());
85	    for (size_t isubchild = 0;
86	         isubchild < module_manager.io_children(child).size(); ++isubchild) {
87	      /* Note that we should use the subchild module when checking the GPIO
88	       * ports. The child module is actually the grid-level I/O module, while
89	       * the subchild module is the subtile inside grid-level I/O modules. Note
90	       * that grid-level I/O module contains all the GPIO ports while the
91	       * subtile may have part of it. For example, a grid I/O module may have 24
92	       * GPINs and 12 GPOUTs, while the first subtile only have 4 GPINs, and the
93	       * second subtile only have 3 GPOUTs. Therefore, to accurately build the
94	       * I/O location map downto subtile level, we need to check the subchild
95	       * module here.
96	       */
97	      ModuleId subchild = module_manager.io_children(child)[isubchild];
98	      vtr::Point<int> subchild_coord =
99	        module_manager.io_child_coordinates(child)[isubchild];
100	
101	      for (const ModuleManager::e_module_port_type& module_io_port_type :
102	           MODULE_IO_PORT_TYPES) {
103	        for (const ModulePortId& gpio_port_id :
104	             module_manager.module_port_ids_by_type(subchild,
105	                                                    module_io_port_type)) {
106	          /* Only care mappable I/O */
107	          if (false ==
108	              module_manager.port_is_mappable_io(subchild, gpio_port_id)) {
109	            continue;
110	          }
111	          const BasicPort& gpio_port =
112	            module_manager.module_port(subchild, gpio_port_id);
113	
114	          auto curr_io_index = io_counter.find(gpio_port.get_name());
115	          /* Index always start from zero */
116	          if (curr_io_index == io_counter.end()) {
117	            io_counter[gpio_port.get_name()] = 0;
118	          }
119	          io_location_map.set_io_index(coord.x(), coord.y(), subchild_coord.x(),
120	                                       gpio_port.get_name(),
121	                                       io_counter[gpio_port.get_name()]);
122	          io_counter[gpio_port.get_name()]++;
123	        }
124	      }
125	    }
126	  }
127	
128	  /* Check all the GPIO ports in the top-level module has been mapped */
129	  for (const ModuleManager::e_module_port_type& module_io_port_type :
130	       MODULE_IO_PORT_TYPES) {
131	    for (const ModulePortId& gpio_port_id :
132	         module_manager.module_port_ids_by_type(top_module,
133	                                                module_io_port_type)) {
134	      /* Only care mappable I/O */
135	      if (false ==
136	          module_manager.port_is_mappable_io(top_module, gpio_port_id)) {
137	        continue;
138	      }
139	
140	      const BasicPort& gpio_port =
141	        module_manager.module_port(top_module, gpio_port_id);
142	      VTR_ASSERT(io_counter[gpio_port.get_name()] == gpio_port.get_width());
143	    }
144	  }
145	
146	  return io_location_map;
147	}
148	
149	/********************************************************************
150	 * Find all the GPIO ports in the tile modules
151	 * and cache their port/pin index in the top-level module
152	 *
153	 * .. note:: The I/O sequence(indexing) is already determined in the
154	 *io_children() list of top-level module. Here we just build a fast lookup from
155	 *(x, y, z) coordinate to the actual indices
156	 *******************************************************************/
157	static IoLocationMap build_fabric_tiled_io_location_map(
158	  const ModuleManager& module_manager, const DeviceGrid& grids,
159	  const size_t& layer) {
160	  vtr::ScopedStartFinishTimer timer(
161	    "Create I/O location mapping for top module");
162	
163	  IoLocationMap io_location_map;
164	
165	  std::map<std::string, size_t> io_counter;
166	
167	  std::string top_module_name = generate_fpga_top_module_name();
168	  ModuleId top_module = module_manager.find_module(top_module_name);
169	  VTR_ASSERT(true == module_manager.valid_module_id(top_module));
170	
171	  /* Walk through the I/O child list */
172	  for (size_t ichild = 0;
173	       ichild < module_manager.io_children(top_module).size(); ++ichild) {
174	    ModuleId child = module_manager.io_children(top_module)[ichild];
175	    vtr::Point<int> coord =
176	      module_manager.io_child_coordinates(top_module)[ichild];
177	    t_physical_tile_loc phy_tile_loc(coord.x(), coord.y(), layer);
178	    t_physical_tile_type_ptr phy_tile_type =
179	      grids.get_physical_type(phy_tile_loc);
180	
181	    /* Bypass EMPTY grid */
182	    if (true == is_empty_type(phy_tile_type)) {
183	      continue;
184	    }
185	
186	    /* Skip width or height > 1 tiles (mostly heterogeneous blocks) */
187	    if ((0 < grids.get_width_offset(phy_tile_loc)) ||
188	        (0 < grids.get_height_offset(phy_tile_loc))) {
189	      continue;
190	    }
191	
192	    VTR_ASSERT_SAFE(true == module_manager.valid_module_id(child));
193	
194	    /* Find all the GPIO ports in the grid module */
195	
196	    /* MUST DO: register in io location mapping!
197	     * I/O location mapping is a critical look-up for testbench generators
198	     */
199	    for (ModuleId tile_child : module_manager.io_children(child)) {
200	      /* Note that we should use the subchild of the subchild module when
201	       * checking the GPIO ports. The child module is the tile module while the
202	       * subchild module is actually the grid-level I/O module, while the
203	       * subchild module is the subtile inside grid-level I/O modules. Note that
204	       * grid-level I/O module contains all the GPIO ports while the subtile may
205	       * have part of it. For example, a grid I/O module may have 24 GPINs and
206	       * 12 GPOUTs, while the first subtile only have 4 GPINs, and the second
207	       * subtile only have 3 GPOUTs. Therefore, to accurately build the I/O
208	       * location map downto subtile level, we need to check the subchild module
209	       * here.
210	       */
211	      if (size_t(phy_tile_type->capacity) !=
212	          module_manager.io_children(tile_child).size()) {
213	        VTR_LOG("%s[%ld][%ld] capacity: %d while io_child number is %d",
214	                phy_tile_type->name.c_str(), coord.x(), coord.y(),
215	                phy_tile_type->capacity,
216	                module_manager.io_children(tile_child).size());
217	      }
218	      VTR_ASSERT(size_t(phy_tile_type->capacity) ==
219	                 module_manager.io_children(tile_child).size());
220	      for (size_t isubchild = 0;
221	           isubchild < module_manager.io_children(tile_child).size();
222	           ++isubchild) {
223	        ModuleId subchild = module_manager.io_children(tile_child)[isubchild];
224	        vtr::Point<int> subchild_coord =
225	          module_manager.io_child_coordinates(tile_child)[isubchild];
226	
227	        for (const ModuleManager::e_module_port_type& module_io_port_type :
228	             MODULE_IO_PORT_TYPES) {
229	          for (const ModulePortId& gpio_port_id :
230	               module_manager.module_port_ids_by_type(subchild,
231	                                                      module_io_port_type)) {
232	            /* Only care mappable I/O */
233	            if (false ==
234	                module_manager.port_is_mappable_io(subchild, gpio_port_id)) {
235	              continue;
236	            }
237	            const BasicPort& gpio_port =
238	              module_manager.module_port(subchild, gpio_port_id);
239	
240	            auto curr_io_index = io_counter.find(gpio_port.get_name());
241	            /* Index always start from zero */
242	            if (curr_io_index == io_counter.end()) {
243	              io_counter[gpio_port.get_name()] = 0;
244	            }
245	            /* This is a dirty hack! */
246	            io_location_map.set_io_index(
247	              coord.x(), coord.y(), subchild_coord.x(), gpio_port.get_name(),
248	              io_counter[gpio_port.get_name()]);
249	            io_counter[gpio_port.get_name()]++;
250	          }
251	        }
252	      }
253	    }
254	  }
255	
256	  /* Check all the GPIO ports in the top-level module has been mapped */
257	  for (const ModuleManager::e_module_port_type& module_io_port_type :
258	       MODULE_IO_PORT_TYPES) {
259	    for (const ModulePortId& gpio_port_id :
260	         module_manager.module_port_ids_by_type(top_module,
261	                                                module_io_port_type)) {
262	      /* Only care mappable I/O */
