1	#ifndef FABRIC_KEY_H
2	#define FABRIC_KEY_H
3	
4	/********************************************************************
5	 * This file include the declaration of fabric key
6	 *******************************************************************/
7	#include <array>
8	#include <map>
9	#include <string>
10	
11	/* Headers from vtrutil library */
12	#include "vtr_geometry.h"
13	#include "vtr_vector.h"
14	
15	/* Headers from openfpgautil library */
16	#include "fabric_key_fwd.h"
17	#include "openfpga_port.h"
18	
19	namespace openfpga {  // Begin namespace openfpga
20	
21	/********************************************************************
22	 * A data structure to describe a secure key for fabric organization
23	 * A fabric may consist of multiple regions
24	 * Each region contains a number of keys
25	 *
26	 * Note that:
27	 *   - each key can only be defined in one unique region
28	 *
29	 * Typical usage:
30	 * --------------
31	 *   // Create an empty fabric key
32	 *   FabricKey fabric_key;
33	 *   // Create a region
34	 *   FabricRegionId region = fabric_key.create_region();
35	 *   // Add a key with name and value
36	 *   FabricKeyId key = fabric_key.create_key(key_name, key_value);
37	 *   // Affilate a key to a region
38	 *   fabric_key.add_key_to_region(region, key);
39	 *
40	 *******************************************************************/
41	class FabricKey {
42	 public: /* Types */
43	  typedef vtr::vector<FabricKeyId, FabricKeyId>::const_iterator
44	    fabric_key_iterator;
45	  typedef vtr::vector<FabricRegionId, FabricRegionId>::const_iterator
46	    fabric_region_iterator;
47	  typedef vtr::vector<FabricBitLineBankId, FabricBitLineBankId>::const_iterator
48	    fabric_bit_line_bank_iterator;
49	  typedef vtr::vector<FabricWordLineBankId,
50	                      FabricWordLineBankId>::const_iterator
51	    fabric_word_line_bank_iterator;
52	  typedef vtr::vector<FabricSubKeyId, FabricSubKeyId>::const_iterator
53	    fabric_sub_key_iterator;
54	  typedef vtr::vector<FabricKeyModuleId, FabricKeyModuleId>::const_iterator
55	    fabric_key_module_iterator;
56	  /* Create range */
57	  typedef vtr::Range<fabric_region_iterator> fabric_region_range;
58	  typedef vtr::Range<fabric_key_iterator> fabric_key_range;
59	  typedef vtr::Range<fabric_bit_line_bank_iterator> fabric_bit_line_bank_range;
60	  typedef vtr::Range<fabric_word_line_bank_iterator>
61	    fabric_word_line_bank_range;
62	  typedef vtr::Range<fabric_sub_key_iterator> fabric_sub_key_range;
63	  typedef vtr::Range<fabric_key_module_iterator> fabric_key_module_range;
64	
65	 public: /* Constructors */
66	  FabricKey();
67	
68	 public: /* Accessors: aggregates */
69	  fabric_key_range keys() const;
70	  fabric_region_range regions() const;
71	  fabric_bit_line_bank_range bl_banks(const FabricRegionId& region_id) const;
72	  fabric_word_line_bank_range wl_banks(const FabricRegionId& region_id) const;
73	  fabric_key_module_range modules() const;
74	  std::vector<FabricSubKeyId> sub_keys(
75	    const FabricKeyModuleId& module_id) const;
76	
77	 public: /* Public Accessors: Basic data query */
78	  size_t num_regions() const;
79	  size_t num_keys() const;
80	  /* Access all the keys of a region */
81	  std::vector<FabricKeyId> region_keys(const FabricRegionId& region_id) const;
82	  /* Access the name of a key */
83	  std::string key_name(const FabricKeyId& key_id) const;
84	  /* Access the value of a key */
85	  size_t key_value(const FabricKeyId& key_id) const;
86	  /* Access the alias of a key */
87	  std::string key_alias(const FabricKeyId& key_id) const;
88	  /* Access the coordinate of a key */
89	  vtr::Point<int> key_coordinate(const FabricKeyId& key_id) const;
90	
91	  /** @brief Find valid key ids for a given alias. Note that you should NOT send
92	   * an empty alias which may cause a complete list of key ids to be returned
93	   * (extremely inefficent and NOT useful). Suggest to check if the existing
94	   * fabric key contains valid alias for each key before calling this API!!! */
95	  std::vector<FabricKeyId> find_key_by_alias(const std::string& alias) const;
96	
97	  /* Check if there are any keys */
98	  bool empty() const;
99	
100	  /* Return a list of data ports which will be driven by a BL shift register
101	   * bank */
102	  std::vector<BasicPort> bl_bank_data_ports(
103	    const FabricRegionId& region_id, const FabricBitLineBankId& bank_id) const;
104	
105	  /* Return a list of data ports which will be driven by a WL shift register
106	   * bank */
107	  std::vector<BasicPort> wl_bank_data_ports(
108	    const FabricRegionId& region_id, const FabricWordLineBankId& bank_id) const;
109	
110	  std::string module_name(const FabricKeyModuleId& module_id) const;
111	  std::string sub_key_name(const FabricSubKeyId& key_id) const;
112	  size_t sub_key_value(const FabricSubKeyId& key_id) const;
113	  std::string sub_key_alias(const FabricSubKeyId& key_id) const;
114	
115	 public: /* Public Mutators: model-related */
116	  /* Reserve a number of regions to be memory efficent */
117	  void reserve_regions(const size_t& num_regions);
118	
119	  /* Create a new region and add it to the library, return an id */
120	  FabricRegionId create_region();
121	
122	  /* Reserve the memory space for keys under a region, to be memory efficient */
123	  void reserve_region_keys(const FabricRegionId& region_id,
124	                           const size_t& num_keys);
125	
126	  /* Add a key to a region */
127	  void add_key_to_region(const FabricRegionId& region_id,
128	                         const FabricKeyId& key_id);
129	
130	  /* Reserve a number of keys to be memory efficent */
131	  void reserve_keys(const size_t& num_keys);
132	
133	  /* Create a new key and add it to the library, return an id */
134	  FabricKeyId create_key();
135	
136	  /* Configure attributes of a key */
137	  void set_key_name(const FabricKeyId& key_id, const std::string& name);
138	  void set_key_value(const FabricKeyId& key_id, const size_t& value);
139	  void set_key_alias(const FabricKeyId& key_id, const std::string& alias);
140	  void set_key_coordinate(const FabricKeyId& key_id,
141	                          const vtr::Point<int>& coord);
142	
143	  /* Reserve a number of banks to be memory efficent */
144	  void reserve_bl_shift_register_banks(const FabricRegionId& region_id,
145	                                       const size_t& num_banks);
146	  void reserve_wl_shift_register_banks(const FabricRegionId& region_id,
147	                                       const size_t& num_banks);
148	
149	  /* Create a new shift register bank for BLs and return an id */
150	  FabricBitLineBankId create_bl_shift_register_bank(
151	    const FabricRegionId& region_id);
152	
153	  /* Add a data port to a given BL shift register bank */
154	  void add_data_port_to_bl_shift_register_bank(
155	    const FabricRegionId& region_id, const FabricBitLineBankId& bank_id,
156	    const BasicPort& data_port);
157	
158	  /* Create a new shift register bank for WLs and return an id */
159	  FabricWordLineBankId create_wl_shift_register_bank(
160	    const FabricRegionId& region_id);
161	
162	  /* Add a data port to a given WL shift register bank */
163	  void add_data_port_to_wl_shift_register_bank(
164	    const FabricRegionId& region_id, const FabricWordLineBankId& bank_id,
165	    const BasicPort& data_port);
166	
167	  /* Reserve a number of keys to be memory efficent */
168	  void reserve_modules(const size_t& num_modules);
169	  void reserve_module_keys(const FabricKeyModuleId& module_id,
170	                           const size_t& num_keys);
171	  /* Create a new key and add it to the library, return an id */
172	  FabricKeyModuleId create_module(const std::string& name);
173	  FabricSubKeyId create_module_key(const FabricKeyModuleId& module_id);
174	  /* Configure attributes of a sub key */
175	  void set_sub_key_name(const FabricSubKeyId& key_id, const std::string& name);
176	  void set_sub_key_value(const FabricSubKeyId& key_id, const size_t& value);
177	  void set_sub_key_alias(const FabricSubKeyId& key_id,
178	                         const std::string& alias);
179	
180	 public: /* Public invalidators/validators */
181	  bool valid_region_id(const FabricRegionId& region_id) const;
182	  bool valid_key_id(const FabricKeyId& key_id) const;
183	  /* Identify if key coordinate is acceptable to fabric key convention */
184	  bool valid_key_coordinate(const vtr::Point<int>& coord) const;
185	  bool valid_bl_bank_id(const FabricRegionId& region_id,
186	                        const FabricBitLineBankId& bank_id) const;
187	  bool valid_wl_bank_id(const FabricRegionId& region_id,
188	                        const FabricWordLineBankId& bank_id) const;
189	  bool valid_module_id(const FabricKeyModuleId& module_id) const;
190	  bool valid_sub_key_id(const FabricSubKeyId& sub_key_id) const;
191	
192	 private: /* Internal data */
193	  /* ---- Top-level keys and regions ---- */
194	  /* Unique ids for each region */
195	  vtr::vector<FabricRegionId, FabricRegionId> region_ids_;
196	  /* Key ids for each region */
197	  vtr::vector<FabricRegionId, std::vector<FabricKeyId>> region_key_ids_;
198	
199	  /* Unique ids for each key */
200	  vtr::vector<FabricKeyId, FabricKeyId> key_ids_;
201	  /* Names for each key */
202	  vtr::vector<FabricKeyId, std::string> key_names_;
203	  /* Values for each key */
204	  vtr::vector<FabricKeyId, size_t> key_values_;
205	  /* Values for each key */
206	  vtr::vector<FabricKeyId, vtr::Point<int>> key_coordinates_;
207	  /* Region for each key */
208	  vtr::vector<FabricKeyId, FabricRegionId> key_regions_;
209	  /* Optional alias for each key, with which a key can also be represented */
210	  vtr::vector<FabricKeyId, std::string> key_alias_;
211	
212	  /* Unique ids for each BL shift register bank */
213	  vtr::vector<FabricRegionId,
214	              vtr::vector<FabricBitLineBankId, FabricBitLineBankId>>
215	    bl_bank_ids_;
216	  /* Data ports to be connected to each BL shift register bank */
217	  vtr::vector<FabricRegionId,
218	              vtr::vector<FabricBitLineBankId, std::vector<BasicPort>>>
219	    bl_bank_data_ports_;
220	
221	  /* Unique ids for each WL shift register bank */
222	  vtr::vector<FabricRegionId,
223	              vtr::vector<FabricWordLineBankId, FabricWordLineBankId>>
224	    wl_bank_ids_;
225	  /* Data ports to be connected to each WL shift register bank */
226	  vtr::vector<FabricRegionId,
227	              vtr::vector<FabricWordLineBankId, std::vector<BasicPort>>>
228	    wl_bank_data_ports_;
229	
230	  /* ---- List of sub modules ---- */
231	  vtr::vector<FabricKeyModuleId, FabricKeyModuleId> sub_key_module_ids_;
232	  vtr::vector<FabricKeyModuleId, std::string> sub_key_module_names_;
233	  vtr::vector<FabricKeyModuleId, std::vector<FabricSubKeyId>> module_sub_keys_;
234	  std::map<std::string, FabricKeyModuleId> module2subkey_lookup_;
235	
236	  /* ---- Sub keys ---- */
