238	  vtr::vector<FabricSubKeyId, std::string> sub_key_names_;
239	  vtr::vector<FabricSubKeyId, size_t> sub_key_values_;
240	  vtr::vector<FabricSubKeyId, std::string> sub_key_alias_;
241	};
