1	/********************************************************************
2	 * This file includes functions that outputs a configuration protocol to XML
3	 *format
4	 *******************************************************************/
5	/* Headers from system goes first */
6	#include <algorithm>
7	#include <string>
8	
9	/* Headers from vtr util library */
10	#include "vtr_assert.h"
11	#include "vtr_log.h"
12	#include "vtr_time.h"
13	
14	/* Headers from openfpga util library */
15	#include "openfpga_digest.h"
16	#include "openfpga_reserved_words.h"
17	
18	/* Headers from arch openfpga library */
19	#include "write_xml_utils.h"
20	
21	/* Headers from fabrickey library */
22	#include "fabric_key_xml_constants.h"
23	#include "write_xml_fabric_key.h"
24	
25	namespace openfpga {  // Begin namespace openfpga
26	
27	/********************************************************************
28	 * A writer to output a component sub key to XML format
29	 *
30	 * Return 0 if successful
31	 * Return 1 if there are more serious bugs in the architecture
32	 * Return 2 if fail when creating files
33	 *******************************************************************/
34	static int write_xml_fabric_component_sub_key(
35	  std::fstream& fp, const FabricKey& fabric_key,
36	  const FabricSubKeyId& component_key, const size_t& key_idx,
37	  const size_t& level) {
38	  /* Validate the file stream */
39	  if (false == openfpga::valid_file_stream(fp)) {
40	    return 2;
41	  }
42	
43	  openfpga::write_tab_to_file(fp, level);
44	  fp << "<" << XML_FABRIC_KEY_KEY_NODE_NAME;
45	
46	  if (false == fabric_key.valid_sub_key_id(component_key)) {
47	    return 1;
48	  }
49	
50	  write_xml_attribute(fp, XML_FABRIC_KEY_KEY_ATTRIBUTE_ID_NAME, key_idx);
51	  if (!fabric_key.sub_key_name(component_key).empty()) {
52	    write_xml_attribute(fp, XML_FABRIC_KEY_KEY_ATTRIBUTE_NAME_NAME,
53	                        fabric_key.sub_key_name(component_key).c_str());
54	  }
55	  write_xml_attribute(fp, XML_FABRIC_KEY_KEY_ATTRIBUTE_VALUE_NAME,
56	                      fabric_key.sub_key_value(component_key));
57	
58	  if (!fabric_key.sub_key_alias(component_key).empty()) {
59	    write_xml_attribute(fp, XML_FABRIC_KEY_KEY_ATTRIBUTE_ALIAS_NAME,
60	                        fabric_key.sub_key_alias(component_key).c_str());
61	  }
62	
63	  fp << "/>"
64	     << "\n";
65	
66	  return 0;
67	}
68	
69	/********************************************************************
70	 * A writer to output a component key to XML format
71	 *
72	 * Return 0 if successful
73	 * Return 1 if there are more serious bugs in the architecture
74	 * Return 2 if fail when creating files
75	 *******************************************************************/
76	static int write_xml_fabric_component_key(std::fstream& fp,
77	                                          const FabricKey& fabric_key,
78	                                          const FabricKeyId& component_key,
79	                                          const size_t& level) {
80	  /* Validate the file stream */
81	  if (false == openfpga::valid_file_stream(fp)) {
82	    return 2;
83	  }
84	
85	  openfpga::write_tab_to_file(fp, level);
86	  fp << "<" << XML_FABRIC_KEY_KEY_NODE_NAME;
87	
88	  if (false == fabric_key.valid_key_id(component_key)) {
89	    return 1;
90	  }
91	
92	  write_xml_attribute(fp, XML_FABRIC_KEY_KEY_ATTRIBUTE_ID_NAME,
93	                      size_t(component_key));
94	  if (!fabric_key.key_name(component_key).empty()) {
95	    write_xml_attribute(fp, XML_FABRIC_KEY_KEY_ATTRIBUTE_NAME_NAME,
96	                        fabric_key.key_name(component_key).c_str());
97	  }
98	  write_xml_attribute(fp, XML_FABRIC_KEY_KEY_ATTRIBUTE_VALUE_NAME,
99	                      fabric_key.key_value(component_key));
100	
101	  if (!fabric_key.key_alias(component_key).empty()) {
102	    write_xml_attribute(fp, XML_FABRIC_KEY_KEY_ATTRIBUTE_ALIAS_NAME,
103	                        fabric_key.key_alias(component_key).c_str());
104	  }
105	
106	  vtr::Point<int> coord = fabric_key.key_coordinate(component_key);
107	  if (fabric_key.valid_key_coordinate(coord)) {
108	    write_xml_attribute(fp, XML_FABRIC_KEY_KEY_ATTRIBUTE_COLUMN_NAME,
109	                        coord.x());
110	    write_xml_attribute(fp, XML_FABRIC_KEY_KEY_ATTRIBUTE_ROW_NAME, coord.y());
111	  }
112	
113	  fp << "/>"
114	     << "\n";
115	
116	  return 0;
117	}
118	
119	/********************************************************************
120	 * A writer to output a BL shift register bank description to XML format
121	 *
122	 * Return 0 if successful
123	 * Return 1 if there are more serious bugs in the architecture
124	 * Return 2 if fail when creating files
125	 *******************************************************************/
126	static int write_xml_fabric_bl_shift_register_banks(
127	  std::fstream& fp, const FabricKey& fabric_key, const FabricRegionId& region,
128	  const size_t& level) {
129	  /* Validate the file stream */
130	  if (false == openfpga::valid_file_stream(fp)) {
131	    return 2;
132	  }
133	
134	  /* If we have an empty bank, we just skip it */
135	  if (0 == fabric_key.bl_banks(region).size()) {
136	    return 0;
137	  }
138	
139	  /* Write the root node */
140	  openfpga::write_tab_to_file(fp, level);
141	  fp << "<" << XML_FABRIC_KEY_BL_SHIFT_REGISTER_BANKS_NODE_NAME << ">"
142	     << "\n";
143	
144	  for (const auto& bank : fabric_key.bl_banks(region)) {
145	    openfpga::write_tab_to_file(fp, level + 1);
146	    fp << "<" << XML_FABRIC_KEY_BLWL_SHIFT_REGISTER_BANK_NODE_NAME;
147	
148	    write_xml_attribute(
149	      fp, XML_FABRIC_KEY_BLWL_SHIFT_REGISTER_BANK_ATTRIBUTE_ID_NAME,
150	      size_t(bank));
151	
152	    std::string port_str;
153	    for (const auto& port : fabric_key.bl_bank_data_ports(region, bank)) {
154	      port_str += generate_xml_port_name(port) + ",";
155	    }
156	    /* Chop the last comma */
157	    if (!port_str.empty()) {
158	      port_str.pop_back();
159	    }
160	    write_xml_attribute(
161	      fp, XML_FABRIC_KEY_BLWL_SHIFT_REGISTER_BANK_ATTRIBUTE_RANGE_NAME,
162	      port_str.c_str());
163	
164	    fp << "/>"
165	       << "\n";
166	  }
167	
168	  openfpga::write_tab_to_file(fp, level);
169	  fp << "</" << XML_FABRIC_KEY_BL_SHIFT_REGISTER_BANKS_NODE_NAME << ">"
170	     << "\n";
171	
172	  return 0;
173	}
174	
175	/********************************************************************
176	 * A writer to output a WL shift register bank description to XML format
177	 *
178	 * Return 0 if successful
179	 * Return 1 if there are more serious bugs in the architecture
180	 * Return 2 if fail when creating files
181	 *******************************************************************/
182	static int write_xml_fabric_wl_shift_register_banks(
183	  std::fstream& fp, const FabricKey& fabric_key, const FabricRegionId& region,
184	  const size_t& level) {
185	  /* Validate the file stream */
186	  if (false == openfpga::valid_file_stream(fp)) {
187	    return 2;
188	  }
189	
190	  /* If we have an empty bank, we just skip it */
191	  if (0 == fabric_key.wl_banks(region).size()) {
192	    return 0;
193	  }
194	
195	  /* Write the root node */
196	  openfpga::write_tab_to_file(fp, level);
197	  fp << "<" << XML_FABRIC_KEY_WL_SHIFT_REGISTER_BANKS_NODE_NAME << ">"
198	     << "\n";
199	
200	  for (const auto& bank : fabric_key.wl_banks(region)) {
201	    openfpga::write_tab_to_file(fp, level + 1);
202	    fp << "<" << XML_FABRIC_KEY_BLWL_SHIFT_REGISTER_BANK_NODE_NAME;
203	
204	    write_xml_attribute(
205	      fp, XML_FABRIC_KEY_BLWL_SHIFT_REGISTER_BANK_ATTRIBUTE_ID_NAME,
206	      size_t(bank));
207	
208	    std::string port_str;
209	    for (const auto& port : fabric_key.wl_bank_data_ports(region, bank)) {
210	      port_str += generate_xml_port_name(port) + ",";
211	    }
212	    /* Chop the last comma */
213	    if (!port_str.empty()) {
214	      port_str.pop_back();
215	    }
216	    write_xml_attribute(
217	      fp, XML_FABRIC_KEY_BLWL_SHIFT_REGISTER_BANK_ATTRIBUTE_RANGE_NAME,
218	      port_str.c_str());
219	
220	    fp << "/>"
221	       << "\n";
222	  }
223	
224	  openfpga::write_tab_to_file(fp, level);
225	  fp << "</" << XML_FABRIC_KEY_WL_SHIFT_REGISTER_BANKS_NODE_NAME << ">"
226	     << "\n";
227	
228	  return 0;
229	}
230	
231	/* Write keys under the top-level module to a file */
232	static int write_xml_top_module_keys(std::fstream& fp,
