105	/********************************************************************
106	 * Build the module graph for FPGA device
107	 *******************************************************************/
108	template <class T>
109	int build_fabric_template(T& openfpga_ctx, const Command& cmd,
110	                          const CommandContext& cmd_context) {
111	  CommandOptionId opt_frame_view = cmd.option("frame_view");
112	  CommandOptionId opt_compress_routing = cmd.option("compress_routing");
113	  CommandOptionId opt_duplicate_grid_pin = cmd.option("duplicate_grid_pin");
114	  CommandOptionId opt_gen_random_fabric_key =
115	    cmd.option("generate_random_fabric_key");
116	  CommandOptionId opt_write_fabric_key = cmd.option("write_fabric_key");
117	  CommandOptionId opt_load_fabric_key = cmd.option("load_fabric_key");
118	  CommandOptionId opt_group_tile = cmd.option("group_tile");
119	  CommandOptionId opt_group_config_block = cmd.option("group_config_block");
120	  CommandOptionId opt_group_routing = cmd.option("group_routing");
121	  CommandOptionId opt_name_module_using_index =
122	    cmd.option("name_module_using_index");
123	  CommandOptionId opt_verbose = cmd.option("verbose");
124	
125	  /* Report conflicts with options:
126	   * - group tile does not support duplicate_grid_pin
127	   * - group tile requires compress_routing to be enabled
128	   */
129	  if (cmd_context.option_enable(cmd, opt_group_tile)) {
130	    if (cmd_context.option_enable(cmd, opt_duplicate_grid_pin)) {
131	      VTR_LOG_ERROR(
132	        "Option '%s' requires options '%s' to be disabled due to a conflict!\n",
133	        cmd.option_name(opt_group_tile).c_str(),
134	        cmd.option_name(opt_duplicate_grid_pin).c_str());
135	      return CMD_EXEC_FATAL_ERROR;
136	    }
137	  }
138	  /* Conflicts: duplicate_grid_pin does not support any port merge */
139	  if (cmd_context.option_enable(cmd, opt_duplicate_grid_pin)) {
140	    if (openfpga_ctx.arch().tile_annotations.tiles_to_merge_ports().size() >
141	        0) {
142	      VTR_LOG_ERROR(
143	        "Option '%s' requires no tile ports to be merged due to a conflict!\n",
144	        cmd.option_name(opt_duplicate_grid_pin).c_str());
145	      return CMD_EXEC_FATAL_ERROR;
146	    }
147	  }
148	
149	  if (true == cmd_context.option_enable(cmd, opt_compress_routing) &&
150	      false == openfpga_ctx.device_rr_gsb().is_compressed()) {
151	    compress_routing_hierarchy_template<T>(
152	      openfpga_ctx, cmd_context.option_enable(cmd, opt_verbose));
153	    /* Update flow manager to enable compress routing */
154	    openfpga_ctx.mutable_flow_manager().set_compress_routing(true);
155	  } else if (true == openfpga_ctx.device_rr_gsb().is_compressed()) {
156	    openfpga_ctx.mutable_flow_manager().set_compress_routing(true);
157	  }
158	
159	  if (cmd_context.option_enable(cmd, opt_group_tile)) {
160	    if (!openfpga_ctx.device_rr_gsb().is_compressed()) {
161	      VTR_LOG_ERROR(
162	        "Option '%s' requires unique blocks to be valid due to a conflict!\n",
163	        cmd.option_name(opt_group_tile).c_str());
164	      return CMD_EXEC_FATAL_ERROR;
165	    }
166	  }
167	  VTR_LOG("\n");
168	
169	  /* Record the execution status in curr_status for each command
170	   * and summarize them in the final status
171	   */
172	  int curr_status = CMD_EXEC_SUCCESS;
173	  int final_status = CMD_EXEC_SUCCESS;
174	
175	  /* Load fabric key from file */
176	  FabricKey predefined_fabric_key;
177	  if (true == cmd_context.option_enable(cmd, opt_load_fabric_key)) {
178	    std::string fkey_fname = cmd_context.option_value(cmd, opt_load_fabric_key);
179	    VTR_ASSERT(false == fkey_fname.empty());
180	    predefined_fabric_key = read_xml_fabric_key(fkey_fname.c_str());
181	  }
182	
183	  VTR_LOG("\n");
184	
185	  /* Build tile-level information:
186	   * - This feature only supports when compress routing is enabled
187	   * - Read the tile organization configuration file
188	   * - Build tile info
189	   */
190	  TileConfig tile_config;
191	  if (cmd_context.option_enable(cmd, opt_group_tile)) {
192	    if (!openfpga_ctx.device_rr_gsb().is_compressed()) {
193	      VTR_LOG_ERROR(
194	        "Group tile is applicable only when compress routing is enabled!\n");
195	      return CMD_EXEC_FATAL_ERROR;
196	    }
197	    curr_status = read_xml_tile_config(
198	      cmd_context.option_value(cmd, opt_group_tile).c_str(), tile_config);
199	    if (CMD_EXEC_SUCCESS != curr_status) {
200	      return CMD_EXEC_FATAL_ERROR;
201	    }
202	  }
203	
204	  curr_status = build_device_module_graph(
205	    openfpga_ctx.mutable_module_graph(), openfpga_ctx.mutable_decoder_lib(),
206	    openfpga_ctx.mutable_blwl_shift_register_banks(),
207	    openfpga_ctx.mutable_fabric_tile(), openfpga_ctx.mutable_module_name_map(),
208	    const_cast<const T&>(openfpga_ctx), g_vpr_ctx.device(),
209	    cmd_context.option_enable(cmd, opt_frame_view),
210	    openfpga_ctx.device_rr_gsb().is_compressed(),
211	    cmd_context.option_enable(cmd, opt_duplicate_grid_pin),
212	    predefined_fabric_key, tile_config,
213	    cmd_context.option_enable(cmd, opt_group_config_block),
214	    cmd_context.option_enable(cmd, opt_group_routing),
215	    cmd_context.option_enable(cmd, opt_name_module_using_index),
216	    cmd_context.option_enable(cmd, opt_gen_random_fabric_key),
217	    cmd_context.option_enable(cmd, opt_verbose));
218	
219	  /* If there is any error, final status cannot be overwritten by a success flag
220	   */
221	  if (CMD_EXEC_SUCCESS != curr_status) {
222	    final_status = curr_status;
223	  }
224	
225	  /* Build I/O location map */
226	  openfpga_ctx.mutable_io_location_map() = build_fabric_io_location_map(
227	    openfpga_ctx.module_graph(), g_vpr_ctx.device().grid,
228	    cmd_context.option_enable(cmd, opt_group_tile));
229	
230	  /* update vpr bitstream annotation with io location map */
231	  const auto io_location_map = openfpga_ctx.io_location_map();
232	  auto& bitstream_annotation = openfpga_ctx.mutable_vpr_bitstream_annotation();
233	  for (const auto& [pb_type, int_pin] :
234	       bitstream_annotation.pb_type_pcf_pins()) {
235	    size_t x = io_location_map.io_x(int_pin);
236	    size_t y = io_location_map.io_y(int_pin);
237	    size_t z = io_location_map.io_z(int_pin);
238	    bool pin_valid = io_location_map.is_valid_coord(x, y, z);
239	    if (!pin_valid) {
240	      VTR_LOG_ERROR("Pin %s defined in pcf command is invalid! \n",
241	                    int_pin.to_verilog_string().c_str());
242	      return CMD_EXEC_FATAL_ERROR;
243	    }
244	    std::array<size_t, 3> coord = {x, y, z};
245	    bitstream_annotation.add_pcf_coord_pb_type(coord, pb_type);
246	  }
247	
248	  /* Build fabric global port information */
249	  openfpga_ctx.mutable_fabric_global_port_info() =
250	    build_fabric_global_port_info(
251	      openfpga_ctx.module_graph(), openfpga_ctx.arch().config_protocol,
252	      openfpga_ctx.arch().tile_annotations, openfpga_ctx.arch().circuit_lib);
253	
254	  /* Output fabric key if user requested */
255	  if (true == cmd_context.option_enable(cmd, opt_write_fabric_key)) {
256	    std::string fkey_fname =
257	      cmd_context.option_value(cmd, opt_write_fabric_key);
258	    VTR_ASSERT(false == fkey_fname.empty());
259	    curr_status = write_fabric_key_to_xml_file(
260	      openfpga_ctx.module_graph(), fkey_fname,
261	      openfpga_ctx.arch().config_protocol,
262	      openfpga_ctx.blwl_shift_register_banks(), false,
263	      cmd_context.option_enable(cmd, opt_verbose));
264	    /* If there is any error, final status cannot be overwritten by a success
265	     * flag */
266	    if (CMD_EXEC_SUCCESS != curr_status) {
267	      final_status = curr_status;
268	    }
269	  }
270	
271	  return final_status;
272	}
