/* namespace openfpga begins */
namespace openfpga {

/********************************************************************
 * A data structure to store necessary information for the global
 * ports that have been defined for the FPGA fabric
 *
 * Currently the global port information is mainly used for testbench generation
 *******************************************************************/
class FabricGlobalPortInfo {
 public: /* Types */
  typedef vtr::vector<FabricGlobalPortId, FabricGlobalPortId>::const_iterator
    global_port_iterator;
  /* Create range */
  typedef vtr::Range<global_port_iterator> global_port_range;

 public: /* Constructor */
  FabricGlobalPortInfo();

 public: /* Public accessors: aggregators */
  global_port_range global_ports() const;

 public: /* Public accessors */
  ModulePortId global_module_port(
    const FabricGlobalPortId& global_port_id) const;
  bool global_port_is_clock(const FabricGlobalPortId& global_port_id) const;
  bool global_port_is_set(const FabricGlobalPortId& global_port_id) const;
  bool global_port_is_reset(const FabricGlobalPortId& global_port_id) const;
  bool global_port_is_prog(const FabricGlobalPortId& global_port_id) const;
  bool global_port_is_bl(const FabricGlobalPortId& global_port_id) const;
  bool global_port_is_wl(const FabricGlobalPortId& global_port_id) const;
  bool global_port_is_shift_register(
    const FabricGlobalPortId& global_port_id) const;
  bool global_port_is_config_enable(
    const FabricGlobalPortId& global_port_id) const;
  bool global_port_is_io(const FabricGlobalPortId& global_port_id) const;
  size_t global_port_default_value(
    const FabricGlobalPortId& global_port_id) const;

 public: /* Public mutators */
  /* By default, we do not set it as a clock.
   * Users should set it through the set_global_port_is_clock() function
   */
  FabricGlobalPortId create_global_port(const ModulePortId& module_port);
  void set_global_port_is_clock(const FabricGlobalPortId& global_port_id,
                                const bool& is_clock);
  void set_global_port_is_set(const FabricGlobalPortId& global_port_id,
                              const bool& is_set);
  void set_global_port_is_reset(const FabricGlobalPortId& global_port_id,
                                const bool& is_reset);
  void set_global_port_is_prog(const FabricGlobalPortId& global_port_id,
                               const bool& is_prog);
  void set_global_port_is_shift_register(
    const FabricGlobalPortId& global_port_id, const bool& is_shift_register);
  void set_global_port_is_bl(const FabricGlobalPortId& global_port_id,
                             const bool& is_bl);
  void set_global_port_is_wl(const FabricGlobalPortId& global_port_id,
                             const bool& is_wl);
  void set_global_port_is_config_enable(
    const FabricGlobalPortId& global_port_id, const bool& is_config_enable);
  void set_global_port_is_io(const FabricGlobalPortId& global_port_id,
                             const bool& is_io);
  void set_global_port_default_value(const FabricGlobalPortId& global_port_id,
                                     const size_t& default_value);

 public: /* Public validator */
  bool valid_global_port_id(const FabricGlobalPortId& global_port_id) const;

 private: /* Internal data */
  /* Global port information for tiles */
  vtr::vector<FabricGlobalPortId, FabricGlobalPortId> global_port_ids_;
  vtr::vector<FabricGlobalPortId, ModulePortId> global_module_ports_;
  vtr::vector<FabricGlobalPortId, bool> global_port_is_clock_;
  vtr::vector<FabricGlobalPortId, bool> global_port_is_reset_;
  vtr::vector<FabricGlobalPortId, bool> global_port_is_set_;
  vtr::vector<FabricGlobalPortId, bool> global_port_is_prog_;
  vtr::vector<FabricGlobalPortId, bool> global_port_is_shift_register_;
  vtr::vector<FabricGlobalPortId, bool> global_port_is_bl_;
  vtr::vector<FabricGlobalPortId, bool> global_port_is_wl_;
  vtr::vector<FabricGlobalPortId, bool> global_port_is_config_enable_;
  vtr::vector<FabricGlobalPortId, bool> global_port_is_io_;
  vtr::vector<FabricGlobalPortId, size_t> global_port_default_values_;

#ifndef MODULE_NAME_MAP_H
#define MODULE_NAME_MAP_H

/********************************************************************
 * Include header files required by the data structure definition
 *******************************************************************/
#include <map>
#include <string>
#include <vector>

/* Begin namespace openfpga */
namespace openfpga {

/**
 * @brief Module name map is a data structure to show mapping between a tag
 * (built-in name) and customized names (may be given by users)
 */
class ModuleNameMap {
 public: /* Public accessors */
  /** @brief Get customized name with a given tag */
  std::string name(const std::string& tag) const;
  /** @brief Check if a name does exist with a given tag. Return true if there
   * is a tag-to-name mapping */
  bool name_exist(const std::string& tag) const;
  /** @brief Check if a tag does exist with a given name. Return true if there
   * is a name-to-tag mapping */
  bool tag_exist(const std::string& name) const;
  /** @brief Get tag with a given name */
  std::string tag(const std::string& name) const;

  /** @brief return a list of all the current keys */
  std::vector<std::string> tags() const;

 public: /* Public mutators */
  /** @brief Create the one-on-one mapping between an built-in name and a
   * customized name. Return 0 for success, return 1 for fail */
  int set_tag_to_name_pair(const std::string& tag, const std::string& name);
  /** @brief Reset to empty status. Clear all the storage */
  void clear();

 private: /* Internal Data */
  /* built-in name -> customized_name
   * Create a double link to check any customized name is mapped to more than 1
   * built-in name!
   */
  std::map<std::string, std::string> tag2names_;
  std::map<std::string, std::string> name2tags_;
};

} /* End namespace openfpga*/

#endif
